#include<bits/stdc++.h>
using namespace std;
int main(void){
    int a[65]={0},b[65]={0},x,y,t;
    cin>>x;
    for(int i=0;i<x;i++)cin>>t,a[t]=1;
	cin>>y;
	for(int i=0;i<y;i++)cin>>t,b[t]=1;
	cout<<x<<"\n";
    for(int i=0;i<65;i++){
    	if(a[i]&&b[i])cout<<i<<' ';
	}cout<<"\n";
	for(int i=0;i<65;i++){
    	if(a[i]||b[i])cout<<i<<' ';
	}cout<<"\n";
    for(int i=0;i<64;i++){
    	if(!a[i])cout<<i<<' ';
	}cout<<"\n";
	bool flag1=true,flag2=true;
	for(int i=0;i<64;i++){
    	if(b[i]!=a[i]){
    		flag1=false;
    		break;
		}
	}cout<<((flag1)?(1):(0))<<"\n";
	for(int i=0;i<64;i++){
    	if(a[i]==1&&b[i]==0){
    		flag2=false;
    		break;
		}
	}cout<<((flag2)?(1):(0))<<"\n";
	cout<<a[0];
    return false;
}
